#include <stdio.h>
#include <limits.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long sum = 0;
        int minVal = INT_MAX;
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            sum += x;
            if (x < minVal) minVal = x;
        }
        printf("%lld\n", sum - minVal);
    }
    return 0;
}

